{
  "summary": "The extraction failed to meet the required accuracy. While the company and address were correctly identified, the date format was incorrect, and both the subtotal and total were mathematically wrong. Furthermore, the line item extraction was incomplete, missing three items and incorrectly merging description fragments (like '[Roll]' and 'Spicy') into the preceding line items.",
  "failure_reasons": [
    "incorrect_date_format",
    "incorrect_subtotal",
    "incorrect_total",
    "incomplete_line_items",
    "incorrect_line_item_description_merging"
  ],
  "field_notes": {
    "date": "Format mismatch: predicted '05-11-2018' instead of '2018-11-05'.",
    "subtotal": "Predicted '18.95' is incorrect; the receipt shows an amount of '27.15'.",
    "total": "Predicted '20.58' is incorrect; the receipt shows a total of '28.78'.",
    "line_items": "The model missed 3 line items and incorrectly concatenated description fragments from separate lines into the descriptions of other items (e.g., '1 13. Shrimp Tempura Roll [Roll]')."
  }
}
